hooks.onDraw:
const s = world.state;
const A = function (v) { return Math.max(0, Math.min(1, v || 0)); };
const PJS = ' "Plus Jakarta Sans", ui-sans-serif, system-ui';
const TAU = Math.PI * 2;
const ls = world.entities.filter(function (e) { return e.type === 'learner'; });
ls.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (const e of ls) world.draw.learner(e);
const nodes = [
  { x: 232, y: 214, l: 'PEDAGOGÍA', sub: 'dirigido por el docente' },
  { x: 460, y: 176, l: 'ANDRAGOGÍA', sub: 'autodirigido' },
  { x: 688, y: 138, l: 'HEUTAGOGÍA', sub: 'autodeterminado' },
];
const stA = [A(s.st1), A(s.st2), A(s.st3)];
ctx.save();
ctx.setLineDash([5, 5]); ctx.strokeStyle = '#7c88aa'; ctx.lineWidth = 2;
for (let i = 0; i < 2; i++) {
  const a = Math.min(stA[i], stA[i + 1]); if (a < 0.02) continue;
  ctx.globalAlpha = a * 0.7;
  ctx.beginPath(); ctx.moveTo(nodes[i].x, nodes[i].y); ctx.lineTo(nodes[i + 1].x, nodes[i + 1].y); ctx.stroke();
}
ctx.setLineDash([]); ctx.restore();
const maxStage = stA[2] > 0.5 ? 3 : (stA[1] > 0.5 ? 2 : (stA[0] > 0.5 ? 1 : 0));
const chip = function (x, y, l, sub, a, active) {
  if (a < 0.01) return;
  ctx.save(); ctx.globalAlpha = a;
  ctx.font = '700 14px' + PJS; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  const w = Math.max(ctx.measureText(l).width, ctx.measureText(sub).width) + 28, h = 44;
  if (active) {
    const g = ctx.createRadialGradient(x, y, 0, x, y, w * 0.75);
    g.addColorStop(0, 'rgba(244,172,29,0.30)'); g.addColorStop(1, 'rgba(244,172,29,0)');
    ctx.fillStyle = g; ctx.beginPath(); ctx.arc(x, y, w * 0.75, 0, TAU); ctx.fill();
  }
  world.draw.rrect(x - w / 2, y - h / 2, w, h, 9); ctx.fillStyle = '#1F2547'; ctx.fill();
  world.draw.rrect(x - w / 2, y - h / 2, w, h, 9);
  ctx.lineWidth = 1.4; ctx.strokeStyle = active ? '#F4AC1D' : 'rgba(232,226,210,0.30)'; ctx.stroke();
  ctx.fillStyle = '#FBFAF6'; ctx.fillText(l, x, y - 6);
  ctx.fillStyle = '#9aa6c8'; ctx.font = '500 10px' + PJS; ctx.fillText(sub, x, y + 12);
  ctx.restore();
};
for (let i = 0; i < 3; i++) chip(nodes[i].x, nodes[i].y, nodes[i].l, nodes[i].sub, stA[i], (i + 1) === maxStage);
const bx = 280, by = 86, bw = 360, bh = 12;
ctx.save();
world.draw.rrect(bx, by, bw, bh, bh / 2); ctx.fillStyle = 'rgba(31,37,71,0.6)'; ctx.fill();
world.draw.rrect(bx, by, bw, bh, bh / 2); ctx.lineWidth = 1; ctx.strokeStyle = 'rgba(232,226,210,0.25)'; ctx.stroke();
const lcx = bx + A(s.locus) * bw;
ctx.fillStyle = '#F4AC1D'; ctx.beginPath(); ctx.arc(lcx, by + bh / 2, 9, 0, TAU); ctx.fill();
ctx.fillStyle = '#fbe9a8'; ctx.beginPath(); ctx.arc(lcx, by + bh / 2, 4, 0, TAU); ctx.fill();
ctx.font = '600 11px' + PJS; ctx.textBaseline = 'middle'; ctx.fillStyle = '#9aa6c8';
ctx.textAlign = 'right'; ctx.fillText('control · DOCENTE', bx - 12, by + bh / 2);
ctx.textAlign = 'left'; ctx.fillText('ESTUDIANTE', bx + bw + 12, by + bh / 2);
ctx.restore();
if (A(s.ejes) > 0.01) {
  ctx.save(); ctx.globalAlpha = A(s.ejes);
  const ejes = ['Currículo flexible', 'Formación docente', 'Acceso equitativo', 'Ética de datos'];
  ctx.font = '600 11px' + PJS; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  for (let i = 0; i < 4; i++) {
    const x = 168 + i * 192, y = 286;
    const w = ctx.measureText(ejes[i]).width + 22, h = 26;
    world.draw.rrect(x - w / 2, y - h / 2, w, h, h / 2); ctx.fillStyle = 'rgba(18,23,42,0.9)'; ctx.fill();
    world.draw.rrect(x - w / 2, y - h / 2, w, h, h / 2); ctx.lineWidth = 1; ctx.strokeStyle = 'rgba(79,208,224,0.5)'; ctx.stroke();
    ctx.fillStyle = '#cfe8ee'; ctx.fillText(ejes[i], x, y + 0.5);
  }
  ctx.restore();
}
